var bc=null,bxCtx=null,bW=0,bH=0,bubbles=[],bubbleAnimId=null;
function initBubbles(){bc=document.getElementById('bubbleCanvas');if(!bc)return;
bxCtx=bc.getContext('2d');function rs(){bW=bc.width=window.innerWidth;bH=bc.height=window.innerHeight}
rs();window.addEventListener('resize',rs);
bubbles=[];for(var i=0;i<30;i++){bubbles.push({
x:Math.random()*bW,y:Math.random()*bH,
r:5+Math.random()*17,s:.3+Math.random()*.4,
vy:-(.1+Math.random()*.2),vx:(Math.random()-.5)*.3
})}startBubbles()}
function startBubbles(){if(!bxCtx)return;function dr(){bxCtx.clearRect(0,0,bW,bH);
bubbles.forEach(function(p){p.y+=p.vy;p.x+=p.vx;
if(p.y<-p.r||p.x<-p.r||p.x>bW+p.r){p.y=bH+p.r;p.x=Math.random()*bW}
bxCtx.globalAlpha=p.s;bxCtx.beginPath();
bxCtx.arc(p.x,p.y,p.r,0,Math.PI*2);
bxCtx.fillStyle='#2d7aff';bxCtx.fill()});
bxCtx.globalAlpha=1;bubbleAnimId=requestAnimationFrame(dr)}
bubbleAnimId=requestAnimationFrame(dr)}
function stopBubbles(){if(bubbleAnimId){cancelAnimationFrame(bubbleAnimId);bubbleAnimId=null}
if(bxCtx){bxCtx.clearRect(0,0,bW,bH)}}

