function gn(){const d=new Date();return d.getFullYear()+String(d.getMonth()+1).padStart(2,'0')+String(d.getDate()).padStart(2,'0')+'ABCDEFGHIJKLMNOPQRSTUVWXYZ'[Math.floor(Math.random()*26)]+'ABCDEFGHIJKLMNOPQRSTUVWXYZ'[Math.floor(Math.random()*26)]}
function gu(){let n='';for(let i=0;i<5;i++)n+=Math.floor(Math.random()*10);const c='ABCDEFGHIJKLMNOPQRSTUVWXYZ';for(let i=0;i<2;i++)n+=c[Math.floor(Math.random()*26)];return n}
