function td(){const d=new Date();return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0')}
function cw(){if(!S.mt)return 0;let v=0;if(S.shp==='square')v=(parseFloat(S.l)||0)*(parseFloat(S.w)||0)*(parseFloat(S.h)||0);else v=Math.PI*((parseFloat(S.d)||0)/2)**2*(parseFloat(S.h2)||0);return(v/1000)*S.mt.de/1000}
function cum(){return cw()*(parseFloat(S.mp)||0)}function ctm(){return cum()*(parseInt(S.q)||1)}
function cpp(p){let h=parseFloat(p.h)||0;if(p.u==='秒')h/=3600;else if(p.u==='分')h/=60;return h*(parseFloat(p.p)||0)}
function ctp(){return S.pr.reduce((s,p)=>s+cpp(p),0)*(parseInt(S.q)||1)}
