var capA=0,capB=0,capOp='+',capAns=0;function genCap(){var ops=['+','-','×','÷'];capOp=ops[Math.floor(Math.random()*4)];if(capOp==='×'){capA=Math.floor(Math.random()*9+1);capB=Math.floor(Math.random()*9+1);capAns=capA*capB}else if(capOp==='÷'){capB=Math.floor(Math.random()*8+2);capA=capB*(Math.floor(Math.random()*8+2));capAns=capA/capB}else{capA=Math.floor(Math.random()*20+1);capB=Math.floor(Math.random()*20+1);if(capOp==='-'){if(capA<capB){var t=capA;capA=capB;capB=t}capAns=capA-capB}else capAns=capA+capB}var q=document.getElementById('capQ');if(q)q.textContent=capA+' '+capOp+' '+capB+' = ?';var i=document.getElementById('capI');if(i)i.value='';var e=document.getElementById('capE');if(e)e.textContent=''}
