function showAbout(){const ov=document.createElement('div');ov.className='mover';ov.style.display='flex';ov.innerHTML='<div class="mbox"><h3>关于我们</h3><div style="font-size:13px;line-height:1.8;color:#666">工价计算器是一款面向中小型机械加工企业的智能化报价辅助工具，服务对象涵盖机床加工、模具制造、五金制品、零部件生产等制造行业。旨在解决传统报价模式中过度依赖技术人员个人经验、流程效率低下、历史数据无法有效复用等长期存在的行业痛点。通过材料成本自动核算、工序费用动态计算、历史订单云端存储与多维度检索等功能，协助企业实现从经验驱动到数据驱动的报价管理模式转变，降低技术门槛，提升经营效率，促进隐性知识的数字化沉淀与传承。<br><br>本应用项目由重庆外语外事学院智能科学与工程学院「拉普拉斯（Laplace）」项目小组研发。<br><br>联系我们：taylorcg@qq.com</div><div class="br" style="margin-top:16px"><button class="btn-p" style="flex:1" id="abC">关闭</button></div></div>';document.body.appendChild(ov);document.getElementById('abC').onclick=()=>document.body.removeChild(ov);ov.addEventListener('click',e=>{if(e.target===ov)document.body.removeChild(ov)})}
